import React from "react";
import "./Login.css";
import TextField from "@material-ui/core/TextField";
import Button from "@material-ui/core/Button";
import CircularProgress from "@material-ui/core/CircularProgress";
import Container from "@material-ui/core/Container";
import Grid from "@material-ui/core/Grid";
import Data from "./Data";

class Login extends React.Component {
  constructor(props) {
    super(props)
    this.state = {
      ip: "",
      isLoading: false,
      lastLoginFailed: false,
    };
  }

  handleChange = (e) => {
    this.setState({ ip: e.target.value});
  };

  checkIP = (e) => {
    var test = Data.state.ip;
    console.log(test)
  };

  keyPress = (e) => {
    if (e.key === "Enter") {
      this.checkIP();
    }
  };

  render() {
    return (
      <div className="Login">
        <Container maxWidth="xs">
          <Grid container spacing={2}>
            <Grid item xs={12}>
              {Data.ip}
            </Grid>
            <Grid item xs={12}>
              <TextField
                id="outlined-basic"
                label="IP Address"
                variant="outlined"
                onChange={this.handleChange}
                onKeyDown={this.keyPress}
                value={Data.ip}
                fullWidth={true}
              />
            </Grid>
            <Grid item xs={12}>
              {!this.state.isLoading && (
                <Button
                  size="large"
                  variant="contained"
                  color="primary"
                  onClick={this.checkIP}
                  fullWidth={true}
                >
                  Login
                </Button>
              )}
            </Grid>
            <Grid item xs={12}>
              {this.state.isLoading && <CircularProgress />}
            </Grid>
            <Grid item xs={12}>
              {this.state.lastLoginFailed && !this.state.isLoading && (
                <p id="error-msg">Last Login attempt was not successful</p>
              )}
            </Grid>
          </Grid>
        </Container>
      </div>
    );
  }
}

export default Login;
